import ipaddress
import socket
import urllib.parse
from typing import Set, Optional, Tuple
import requests
from requests.adapters import HTTPAdapter
from urllib3.util.retry import Retry


class SSRFProtectionAdapter(HTTPAdapter):
    """Custom adapter to prevent SSRF attacks by blocking private IP ranges."""
    
    def __init__(self, allowed_domains: Set[str], *args, **kwargs):
        self.allowed_domains = allowed_domains
        super().__init__(*args, **kwargs)
    
    def send(self, request, *args, **kwargs):
        """Override send to validate destination before making request."""
        parsed_url = urllib.parse.urlparse(request.url)
        hostname = parsed_url.hostname
        
        # Validate domain is in allowlist
        if not self._is_domain_allowed(hostname):
            raise ValueError(f"Domain {hostname} is not in the allowlist")
        
        # Resolve hostname and check IP
        try:
            ip_addresses = socket.getaddrinfo(hostname, None)
            for ip_info in ip_addresses:
                ip_addr = ip_info[4][0]
                if self._is_private_ip(ip_addr):
                    raise ValueError(f"Access to private IP address {ip_addr} is blocked")
        except socket.gaierror:
            raise ValueError(f"Unable to resolve hostname {hostname}")
        
        return super().send(request, *args, **kwargs)
    
    def _is_domain_allowed(self, hostname: str) -> bool:
        """Check if domain is in allowlist."""
        if not hostname:
            return False
        
        # Check exact match
        if hostname in self.allowed_domains:
            return True
        
        # Check wildcard subdomains (e.g., *.example.com)
        for allowed_domain in self.allowed_domains:
            if allowed_domain.startswith('*.'):
                base_domain = allowed_domain[2:]
                if hostname.endswith('.' + base_domain) or hostname == base_domain:
                    return True
        
        return False
    
    def _is_private_ip(self, ip_str: str) -> bool:
        """Check if IP address is private, loopback, or link-local."""
        try:
            ip = ipaddress.ip_address(ip_str)
            return (
                ip.is_private or
                ip.is_loopback or
                ip.is_link_local or
                ip.is_multicast or
                ip.is_reserved or
                ip.is_unspecified
            )
        except ValueError:
            return True  # If we can't parse it, block it


class SecureWebhookFetcher:
    """Secure URL fetcher for webhook processing with SSRF protection."""
    
    def __init__(self, allowed_domains: Set[str], max_redirects: int = 2, timeout: int = 10):
        """
        Initialize the secure fetcher.
        
        Args:
            allowed_domains: Set of allowed domain names (supports wildcards like *.example.com)
            max_redirects: Maximum number of redirects to follow (default: 2)
            timeout: Request timeout in seconds (default: 10)
        """
        self.allowed_domains = allowed_domains
        self.max_redirects = max_redirects
        self.timeout = timeout
        self.session = self._create_session()
    
    def _create_session(self) -> requests.Session:
        """Create a requests session with security configurations."""
        session = requests.Session()
        
        # Configure retry strategy
        retry_strategy = Retry(
            total=3,
            backoff_factor=1,
            status_forcelist=[429, 500, 502, 503, 504],
            allowed_methods=["GET", "POST"]
        )
        
        # Mount custom adapter with SSRF protection
        adapter = SSRFProtectionAdapter(
            allowed_domains=self.allowed_domains,
            max_retries=retry_strategy
        )
        session.mount("http://", adapter)
        session.mount("https://", adapter)
        
        return session
    
    def _validate_url(self, url: str) -> Tuple[bool, Optional[str]]:
        """
        Validate URL format and scheme.
        
        Returns:
            Tuple of (is_valid, error_message)
        """
        try:
            parsed = urllib.parse.urlparse(url)
            
            # Only allow HTTP and HTTPS
            if parsed.scheme not in ['http', 'https']:
                return False, f"Invalid scheme: {parsed.scheme}. Only http and https are allowed"
            
            # Ensure hostname exists
            if not parsed.hostname:
                return False, "URL must contain a valid hostname"
            
            # Block URLs with credentials
            if parsed.username or parsed.password:
                return False, "URLs with embedded credentials are not allowed"
            
            return True, None
        except Exception as e:
            return False, f"Invalid URL format: {str(e)}"
    
    def _validate_redirect(self, response: requests.Response) -> None:
        """Validate redirect responses before following them."""
        if response.is_redirect:
            redirect_url = response.headers.get('Location', '')
            is_valid, error = self._validate_url(redirect_url)
            if not is_valid:
                raise ValueError(f"Invalid redirect URL: {error}")
    
    def fetch_url(self, url: str, method: str = 'GET', headers: Optional[dict] = None, 
                  data: Optional[dict] = None) -> dict:
        """
        Fetch content from a URL with security controls.
        
        Args:
            url: The URL to fetch
            method: HTTP method (GET or POST)
            headers: Optional custom headers
            data: Optional data for POST requests
        
        Returns:
            Dictionary containing response data:
            {
                'status_code': int,
                'content': str,
                'headers': dict,
                'url': str (final URL after redirects)
            }
        """
        # Validate URL format
        is_valid, error = self._validate_url(url)
        if not is_valid:
            raise ValueError(error)
        
        # Prepare headers
        request_headers = {
            'User-Agent': 'SecureWebhookFetcher/1.0',
            'Accept': 'application/json, text/plain, */*'
        }
        if headers:
            request_headers.update(headers)
        
        try:
            # Make request with controlled redirects
            response = self.session.request(
                method=method.upper(),
                url=url,
                headers=request_headers,
                json=data if method.upper() == 'POST' else None,
                timeout=self.timeout,
                allow_redirects=False  # Handle redirects manually
            )
            
            # Handle redirects manually with validation
            redirect_count = 0
            while response.is_redirect and redirect_count < self.max_redirects:
                self._validate_redirect(response)
                redirect_url = response.headers.get('Location', '')
                
                # Handle relative redirects
                if not redirect_url.startswith(('http://', 'https://')):
                    redirect_url = urllib.parse.urljoin(url, redirect_url)
                
                # Validate redirect URL
                is_valid, error = self._validate_url(redirect_url)
                if not is_valid:
                    raise ValueError(f"Invalid redirect: {error}")
                
                response = self.session.request(
                    method='GET',
                    url=redirect_url,
                    headers=request_headers,
                    timeout=self.timeout,
                    allow_redirects=False
                )
                redirect_count += 1
                url = redirect_url
            
            if response.is_redirect:
                raise ValueError(f"Too many redirects (max: {self.max_redirects})")
            
            return {
                'status_code': response.status_code,
                'content': response.text,
                'headers': dict(response.headers),
                'url': url
            }
        
        except requests.exceptions.Timeout:
            raise TimeoutError(f"Request timed out after {self.timeout} seconds")
        except requests.exceptions.ConnectionError as e:
            raise ConnectionError(f"Failed to connect to {url}: {str(e)}")
        except requests.exceptions.RequestException as e:
            raise RuntimeError(f"Request failed: {str(e)}")


def fetch_and_display_url(url: str, allowed_domains: Set[str], 
                          method: str = 'GET', headers: Optional[dict] = None,
                          data: Optional[dict] = None) -> str:
    """
    Fetch and display content from a URL with security controls.
    
    Args:
        url: The URL to fetch
        allowed_domains: Set of allowed domains (e.g., {'api.partner1.com', '*.partner2.com'})
        method: HTTP method (default: GET)
        headers: Optional custom headers
        data: Optional data for POST requests
    
    Returns:
        The content fetched from the URL
    """
    fetcher = SecureWebhookFetcher(allowed_domains=allowed_domains)
    
    try:
        result = fetcher.fetch_url(url, method=method, headers=headers, data=data)
        
        print(f"Status Code: {result['status_code']}")
        print(f"Final URL: {result['url']}")
        print(f"Content Length: {len(result['content'])} bytes")
        print("\nContent:")
        print(result['content'])
        
        return result['content']
    
    except (ValueError, TimeoutError, ConnectionError, RuntimeError) as e:
        print(f"Error fetching URL: {str(e)}")
        raise


# Example usage for webhook processing
def process_webhook(webhook_config: dict, webhook_data: dict) -> str:
    """
    Process a webhook by fetching data from partner API.
    
    Args:
        webhook_config: Configuration containing 'url' and 'partner_domain'
        webhook_data: Data to send in webhook
    
    Returns:
        Response content from partner API
    """
    # Define allowed domains for different partners
    PARTNER_ALLOWLIST = {
        'partner1': {'api.partner1.com', 'webhooks.partner1.com'},
        'partner2': {'*.partner2.io'},
        'partner3': {'api.partner3.net'},
    }
    
    partner = webhook_config.get('partner')
    url = webhook_config.get('url')
    
    if partner not in PARTNER_ALLOWLIST:
        raise ValueError(f"Unknown partner: {partner}")
    
    allowed_domains = PARTNER_ALLOWLIST[partner]
    
    return fetch_and_display_url(
        url=url,
        allowed_domains=allowed_domains,
        method='POST',
        headers={'Content-Type': 'application/json'},
        data=webhook_data
    )